import{_ as o,o as t,c as a,a3 as s}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"178. Shiftwork","description":"","frontmatter":{"title":"178. Shiftwork","eba":"Mental Health Services 2024-2028","topics":["hours","shift-work","allowances","wages"]},"headers":[],"relativePath":"ebas/mental-health/support-services/preliminary/178-shiftwork.md","filePath":"ebas/mental-health/support-services/preliminary/178-shiftwork.md"}'),n={name:"ebas/mental-health/support-services/preliminary/178-shiftwork.md"};function r(i,e,h,l,f,p){return t(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="_178-shiftwork" tabindex="-1">178. Shiftwork <a class="header-anchor" href="#_178-shiftwork" aria-label="Permalink to &quot;178. Shiftwork&quot;">​</a></h1><p><strong>178.1</strong> Employees who perform shift work shall be entitled to payment of the shift allowances applying to their classification under the following provisions of this clause.</p><p><strong>178.2</strong> Change of Shift Allowance</p><p><strong>(a)</strong> An Employee who changes from working on one shift to working on another shift, the time of commencement of which differs by four hours or more than from that of the first, shall be paid a change of shift allowance equal to 4% of the relevant base rate on the occasion of each such change in addition to any amount payable under the preceding provisions of this clause.</p><p><strong>(b)</strong> Notwithstanding the provisions of clause 178.2(a)[194.2(a)] above, the change of shift allowance is not payable where the Employer agrees to a request in writing made on behalf of one or more Employees for changes in shifts.</p><p><strong>(c)</strong> Change of shift allowance is not payable where a single Employee holds two contemporaneous different contracted positions with the same Employer and moving between those positions results in a change of shift pattern which would ordinarily invoke a change of shift allowance payment.</p><p>LEAVE AND PUBLIC HOLIDAYS</p>',7)])])}const w=o(n,[["render",r]]);export{m as __pageData,w as default};
